    pub async fn authenticate(&mut self, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut url: Value = get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &Value::Str("ws".to_string()));
        let mut client: Value = self.client(&[url.clone()]);
        let mut messageHash: Value = Value::Str("authenticated".to_string());
        let mut future: Value = self.safe_value(get_value(&client, &Value::Str("subscriptions".to_string())), messageHash.clone(), &[]);
        if is_equal(&future, &Value::Null) {
            let mut timestamp: Value = self.milliseconds();
            let mut stringTimestamp: Value = to_string_val(&timestamp);
            let mut auth: Value = add(&add(&add(&stringTimestamp, &Value::Str("GET/".to_string())), &self.version), &Value::Str("/websocket".to_string()));
            let mut signature: Value = self.hmac(self.encode(auth.clone()), self.encode(self.secret.clone()), Value::Str("sha256".to_string()), &[]);
            let mut action: Value = Value::Str("authenticate".to_string());
            let mut request: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("action".to_string(), action.clone());
                    m.insert("key".to_string(), self.apiKey.clone());
                    m.insert("signature".to_string(), signature.clone());
                    m.insert("timestamp".to_string(), timestamp.clone());
                m
            });
            let mut message: Value = self.extend(request.clone(), &[params.clone()]);
            future = self.watch(url.clone(), messageHash.clone(), &[message.clone(), messageHash.clone()]).await;
            add_element_to_object(&mut get_value(&client, &Value::Str("subscriptions".to_string())), &messageHash, future.clone());
        }
        return future;

    Value::Null
}

    pub fn handle_authentication_message(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "event": "authenticate",
        //         "authenticated": true
        //     }
        //
        let mut messageHash: Value = Value::Str("authenticated".to_string());
        let mut authenticated: Value = self.safe_bool_k(message.clone(), "authenticated", &[Value::Bool(false)]);
        if is_true(&authenticated) {
            // we resolve the future here permanently so authentication only happens once
            client.resolve(&[message.clone(), messageHash.clone()]);
        }  else {
            let mut error = Value::from(crate::exchange_errors::authentication_error(self.json(message.clone())));
            client.reject(&[Value::from(error.clone()), messageHash.clone()]);
            // allows further authentication attempts
            if is_true(&Value::Bool(in_op(&get_value(&client, &Value::Str("subscriptions".to_string())), &messageHash))) {
                remove(&mut get_value(&client, &Value::Str("subscriptions".to_string())), &messageHash);
            }
        }
}

    pub fn handle_error_message(&self, mut client: Value, mut message: Value) -> Value {
        //
        //    {
        //        action: 'privateCreateOrder',
        //        market: 'BTC-EUR',
        //        errorCode: 217,
        //        error: 'Minimum order size in quote currency is 5 EUR or 0.001 BTC.'
        //    }
        //    {
        //        action: 'privateCreateOrder',
        //        requestId: '17317539426571916',
        //        market: 'USDT-EUR',
        //        errorCode: 216,
        //        error: 'You do not have sufficient balance to complete this operation.'
        //    }
        //
        let mut error: Value = self.safe_string_k(message.clone(), "error", &[]);
        let mut code: Value = self.safe_integer_k(error.clone(), "errorCode", &[]);
        let mut action: Value = self.safe_string_k(message.clone(), "action", &[]);
        let mut buildMessage: Value = self.build_message_hash(action.clone(), &[message.clone()]);
        let mut messageHash: Value = self.safe_string_k(message.clone(), "requestId", &[buildMessage.clone()]);
        let mut rejected: Value = Value::Bool(false);
        let _try_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            self.handle_errors(code.clone(), error.clone(), get_value(&client, &Value::Str("url".to_string())), Value::Str("".to_string()), Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            }), error.clone(), message.clone(), Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            }), Value::Map({
                let mut m = indexmap::IndexMap::new();
                m
            }));
         #[allow(unreachable_code)] { Value::Null }}));
if let Err(_try_err) = _try_result { let e: Value = panic_to_value(_try_err);
            rejected = Value::Bool(true);
            client.reject(&[e.clone(), messageHash.clone()]);
        }
        if !is_true(&rejected) {
            client.reject(&[message.clone(), messageHash.clone()]);
            return Value::Bool(true);
        }
        return Value::Null;

    Value::Null
}

    pub fn handle_message(&self, mut client: Value, mut message: Value) {
        //
        //     {
        //         "event": "subscribed",
        //         "subscriptions": {
        //             "book": [ "BTC-EUR" ]
        //         }
        //     }
        //
        //     {
        //         "event": "book",
        //         "market": "BTC-EUR",
        //         "nonce": 36729561,
        //         "bids": [
        //             [ "8513.3", "0" ],
        //             [ '8518.8', "0.64236203" ],
        //             [ '8513.6', "0.32435481" ],
        //         ],
        //         "asks": []
        //     }
        //
        //     {
        //         "action": "getBook",
        //         "response": {
        //             "market": "BTC-EUR",
        //             "nonce": 36946120,
        //             "bids": [
        //                 [ '8494.9', "0.24399521" ],
        //                 [ '8494.8', "0.34884085" ],
        //                 [ '8493.9', "0.14535128" ],
        //             ],
        //             "asks": [
        //                 [ "8495", "0.46982463" ],
        //                 [ '8495.1', "0.12178267" ],
        //                 [ '8496.2', "0.21924143" ],
        //             ]
        //         }
        //     }
        //
        //     {
        //         "event": "authenticate",
        //         "authenticated": true
        //     }
        //
        let mut error: Value = self.safe_string_k(message.clone(), "error", &[]);
        if !is_equal(&error, &Value::Null) {
            self.handle_error_message(client.clone(), message.clone());
        }
        let mut methods: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("subscribed".to_string(), Value::Null.clone());
                m.insert("book".to_string(), Value::Null.clone());
                m.insert("getBook".to_string(), Value::Null.clone());
                m.insert("trade".to_string(), Value::Null.clone());
                m.insert("candle".to_string(), Value::Null.clone());
                m.insert("ticker24h".to_string(), Value::Null.clone());
                m.insert("authenticate".to_string(), Value::Null.clone());
                m.insert("order".to_string(), Value::Null.clone());
                m.insert("fill".to_string(), Value::Null.clone());
                m.insert("privateCreateOrder".to_string(), Value::Null.clone());
                m.insert("privateUpdateOrder".to_string(), Value::Null.clone());
                m.insert("privateGetBalance".to_string(), Value::Null.clone());
                m.insert("privateCancelOrders".to_string(), Value::Null.clone());
                m.insert("privateGetOrders".to_string(), Value::Null.clone());
                m.insert("privateGetOrder".to_string(), Value::Null.clone());
                m.insert("privateCancelOrder".to_string(), Value::Null.clone());
                m.insert("privateGetOrdersOpen".to_string(), Value::Null.clone());
                m.insert("privateGetAccount".to_string(), Value::Null.clone());
                m.insert("privateGetDepositHistory".to_string(), Value::Null.clone());
                m.insert("privateGetWithdrawalHistory".to_string(), Value::Null.clone());
                m.insert("privateWithdrawAssets".to_string(), Value::Null.clone());
                m.insert("privateGetTrades".to_string(), Value::Null.clone());
                m.insert("getAssets".to_string(), Value::Null.clone());
                m.insert("getCandles".to_string(), Value::Null.clone());
                m.insert("getMarkets".to_string(), Value::Null.clone());
            m
        });
        let mut event: Value = self.safe_string_k(message.clone(), "event", &[]);
        let mut method: Value = self.safe_value(methods.clone(), event.clone(), &[]);
        if is_equal(&method, &Value::Null) {
            let mut action: Value = self.safe_string_k(message.clone(), "action", &[]);
            method = self.safe_value(methods.clone(), action.clone(), &[]);
            if !is_equal(&method, &Value::Null) {
                method.call(&[client.clone(), message.clone()]);
            }
        }  else {
            method.call(&[client.clone(), message.clone()]);
        }
}
